    "extent-1:extent_value": "1 online resource (19 pages ; 28 x 15 cm)",
    "form-1:form_term.value": "manuscripts",
    "internal_note-1:internal_note_value": "Digitized Diem Pham",
    "language-1:language_term.value": "Chinese",
    "local_identifier-1:local_identifier_value": "nlvnpf-0595",
    "marc_005_last_modified-1:marc_005_last_modified_value": "20251224195423.9",
    "name-1:name_role-1:name_role_term.value": "author",
    "name-1:name_term.value": "Phan-bội-Châu, 1867-1940",
    "name-2:name_role-1:name_role_term.value": "",
    "name-2:name_term.value": "",
    "name-3:name_role-1:name_role_term.value": "",
