    "date_issued_textual-1:date_issued_textual_value": "Hoàng triều Tự Đức ngũ niên Nhâm Tý xuân [1852] = 皇朝嗣德五年壬子春 [1852]",
    "extent-1:extent_value": "1 online resource (63 pages ; 24 x 12 cm)",
    "form-1:form_term.value": "manuscripts",
