    "_pid": "cul:qjq2bvqb98",
    "_doi": "doi:10.7916/d8-nzyz-4d12",
    "_thumbnail_url": "https://triclops.library.columbia.edu/iiif/2/featured/cul:7d7wm37t6d/full/!256,256/0/default.jpg",
