    "date_issued_textual-1:date_issued_textual_value": "Tự Đức tam thập tam niên thập nhất nguyệt cung thuyên [1880]",
    "extent-1:extent_value": "1 online resource (86 pages ; 26 x 15 cm)",
    "form-1:form_term.value": "manuscripts",
    "internal_note-1:internal_note_value": "Digitized Giáp Thị Hải Chi",
