    "_pid": "cul:djh9w0vw8g",
    "_doi": "doi:10.7916/d8-6msn-pd33",
    "_thumbnail_url": "https://triclops.library.columbia.edu/iiif/2/featured/cul:w3r2280jw0/full/!256,256/0/default.jpg",
    "alternative_title-1:alternative_title_value": "吾黃甲詩集",
    "alternative_title-2:alternative_title_value": "",
    "clio_identifier-1:clio_identifier_value": "15758624",
    "date_issued-1:date_issued_end_value": "19XX",
