    "internal_note-1:internal_note_value": "",
    "language-1:language_term.value": "Chinese",
    "local_identifier-1:local_identifier_value": "nlvnpf-0679",
    "marc_005_last_modified-1:marc_005_last_modified_value": "20251224195343",
    "name-1:name_role-1:name_role_term.value": "author",
    "name-1:name_term.value": "Ngô, Thì Sĩ, 1726-1780",
    "name-2:name_role-1:name_role_term.value": "",
